ALTER TABLE "SOURCE_SYSTEM_A_OP"."ETL_SANITY_STRUCTURE"  DROP CONSTRAINT FK_DIM_SANITY_CATEGORY;

DROP TABLE "SOURCE_SYSTEM_A_OP"."DIM_SANITY_CATEGORY";

CREATE COLUMN TABLE "SOURCE_SYSTEM_A_OP"."DIM_SANITY_CATEGORY"
(
	 "CATEGORY_ID" INTEGER CS_INT GENERATED BY DEFAULT AS IDENTITY,
	 "NAME"        NVARCHAR(255),
	 "DESCRIPTION" NVARCHAR(2000),
	 "ACTIVE_FLAG" NVARCHAR(1) DEFAULT 'Y',
	 "CREATE_TIMESTAMP" TIMESTAMP DEFAULT current_timestamp,
	 PRIMARY KEY ("CATEGORY_ID")
) UNLOAD PRIORITY 5 AUTO MERGE;


DROP TABLE "SOURCE_SYSTEM_A_OP"."ETL_SANITY_STRUCTURE";

CREATE COLUMN TABLE "SOURCE_SYSTEM_A_OP"."ETL_SANITY_STRUCTURE"
(
	 "ID" INTEGER CS_INT GENERATED BY DEFAULT AS IDENTITY,
	 "SOURCE_DB_NAME"  NVARCHAR(255),
	 "SACK_NODE_LABEL" NVARCHAR(255),
	 "TABLE_NAME"   NVARCHAR(255),
	 "CATEGORY_FK"  INTEGER,
	 "OPERATOR"     NVARCHAR(50),
     "COLUMN_1"     NVARCHAR(255),
	 "COLUMN_2"     NVARCHAR(255),
	 "EXPRESSION_1" NVARCHAR(255),
	 "EXPRESSION_2" NVARCHAR(255),
	 "DESCRIPTION"  NVARCHAR(2000),
	 "CREATED_BY"   NVARCHAR(255),
	 "ACTIVE_FLAG"  NVARCHAR(1) DEFAULT 'Y',
	 "START_DATE"   TIMESTAMP,
	 "END_DATE"     TIMESTAMP DEFAULT '2099-12-31',
	 "CREATE_TIMESTAMP" TIMESTAMP DEFAULT current_timestamp,
	 PRIMARY KEY ("ID")
) UNLOAD PRIORITY 5 AUTO MERGE;

ALTER TABLE "SOURCE_SYSTEM_A_OP"."ETL_SANITY_STRUCTURE"  ADD CONSTRAINT FK_DIM_SANITY_CATEGORY
FOREIGN KEY (CATEGORY_FK) REFERENCES DIM_SANITY_CATEGORY(CATEGORY_ID);

DROP TABLE SOURCE_SYSTEM_A_OP.LOG_SANITY_CHECK;

CREATE COLUMN TABLE SOURCE_SYSTEM_A_OP.LOG_SANITY_CHECK (
   ID                    Integer CS_INT GENERATED BY DEFAULT AS IDENTITY,
   RUN_ID                Integer,
   SANITY_STRUCTURE_ID   INTEGER,
   ROW_GUID              NVARCHAR(50),
   DESCRIPTION           NVARCHAR(255),
   FAILED_AT             Timestamp   DEFAULT current_timestamp,
   RELOAD                NVARCHAR(1) DEFAULT 'N',
   PRIMARY KEY (ID)
);
